import React, { useState } from 'react';
import {
  Box,
  Paper,
  Typography,
  Grid,
  TextField,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Chip,
  Card,
  CardContent,
  Alert,
  LinearProgress,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
} from '@mui/material';
import {
  Search,
  Download,
  Print,
  ShoppingCart,
  Refresh,
  PictureAsPdf,
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import { reportService } from '../../services/reportService';

const PurchaseReport = () => {
  const [filters, setFilters] = useState({
    startDate: new Date(new Date().setDate(1)).toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0],
    dateType: 'INVOICE_DATE',
  });
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [summary, setSummary] = useState(null);

  const fetchReport = async () => {
    if (!filters.startDate || !filters.endDate) {
      setError('Please select both start and end dates');
      return;
    }

    setLoading(true);
    setError('');
    try {
      const response = await reportService.getPurchaseReport(filters);
      setData(response.content || []);
      setSummary(response.summary || null);
      toast.success('Report loaded successfully');
    } catch (error) {
      setError('Failed to load report');
      toast.error('Failed to load report');
    } finally {
      setLoading(false);
    }
  };

  const handleExportExcel = async () => {
    try {
      await reportService.exportPurchaseReport(filters);
      toast.success('Report exported successfully');
    } catch (error) {
      toast.error('Failed to export report');
    }
  };

  return (
    <Box>
      <Box display="flex" alignItems="center" gap={2} mb={3}>
        <ShoppingCart sx={{ fontSize: 40, color: '#1976d2' }} />
        <Box>
          <Typography variant="h4" fontWeight="bold">
            Purchase Report
          </Typography>
          <Typography variant="body2" color="textSecondary">
            View and analyze purchase data
          </Typography>
        </Box>
      </Box>

      {error && (
        <Alert severity="error" sx={{ mb: 3 }} onClose={() => setError('')}>
          {error}
        </Alert>
      )}

      <Paper sx={{ p: 3, borderRadius: 2, mb: 3 }}>
        <Grid container spacing={2} alignItems="center">
          <Grid item xs={12} md={3}>
            <TextField
              fullWidth
              label="Start Date"
              type="date"
              name="startDate"
              value={filters.startDate}
              onChange={(e) => setFilters({ ...filters, startDate: e.target.value })}
              InputLabelProps={{ shrink: true }}
            />
          </Grid>
          <Grid item xs={12} md={3}>
            <TextField
              fullWidth
              label="End Date"
              type="date"
              name="endDate"
              value={filters.endDate}
              onChange={(e) => setFilters({ ...filters, endDate: e.target.value })}
              InputLabelProps={{ shrink: true }}
            />
          </Grid>
          <Grid item xs={12} md={3}>
            <FormControl fullWidth>
              <InputLabel>Date Type</InputLabel>
              <Select
                name="dateType"
                value={filters.dateType}
                onChange={(e) => setFilters({ ...filters, dateType: e.target.value })}
                label="Date Type"
              >
                <MenuItem value="INVOICE_DATE">Invoice Date</MenuItem>
                <MenuItem value="RECEIVED_DATE">Received Date</MenuItem>
              </Select>
            </FormControl>
          </Grid>
          <Grid item xs={12} md={3}>
            <Button
              fullWidth
              variant="contained"
              startIcon={<Search />}
              onClick={fetchReport}
              disabled={loading}
              sx={{ height: 56 }}
            >
              {loading ? 'Loading...' : 'Generate'}
            </Button>
          </Grid>
        </Grid>

        <Box display="flex" gap={1} mt={2} flexWrap="wrap">
          <Button variant="outlined" startIcon={<Refresh />} onClick={fetchReport}>
            Refresh
          </Button>
          <Button variant="outlined" startIcon={<Download />} onClick={handleExportExcel}>
            Excel
          </Button>
          <Button variant="outlined" startIcon={<PictureAsPdf />}>
            PDF
          </Button>
          <Button variant="outlined" startIcon={<Print />}>
            Print
          </Button>
        </Box>
      </Paper>

      {summary && (
        <Grid container spacing={3} mb={3}>
          <Grid item xs={12} md={3}>
            <Card>
              <CardContent>
                <Typography variant="body2" color="textSecondary">
                  Total Purchases
                </Typography>
                <Typography variant="h5" color="primary">
                  ₹{summary.totalPurchases?.toFixed(2)}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid item xs={12} md={3}>
            <Card>
              <CardContent>
                <Typography variant="body2" color="textSecondary">
                  Total Invoices
                </Typography>
                <Typography variant="h5">{summary.totalInvoices}</Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid item xs={12} md={3}>
            <Card>
              <CardContent>
                <Typography variant="body2" color="textSecondary">
                  Total Suppliers
                </Typography>
                <Typography variant="h5">{summary.totalSuppliers}</Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid item xs={12} md={3}>
            <Card>
              <CardContent>
                <Typography variant="body2" color="textSecondary">
                  Average Invoice
                </Typography>
                <Typography variant="h5">
                  ₹{summary.averageInvoice?.toFixed(2)}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
        </Grid>
      )}

      {loading ? (
        <Box sx={{ width: '100%', py: 4 }}>
          <LinearProgress />
        </Box>
      ) : data.length > 0 ? (
        <Paper sx={{ p: 2, borderRadius: 2 }}>
          <TableContainer>
            <Table>
              <TableHead>
                <TableRow sx={{ backgroundColor: '#f5f7fa' }}>
                  <TableCell>Invoice No</TableCell>
                  <TableCell>Date</TableCell>
                  <TableCell>Supplier</TableCell>
                  <TableCell align="right">Amount</TableCell>
                  <TableCell align="right">Discount</TableCell>
                  <TableCell align="right">Tax</TableCell>
                  <TableCell align="right">Net Amount</TableCell>
                  <TableCell>Payment</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {data.map((row, index) => (
                  <TableRow key={index} hover>
                    <TableCell>{row.invoiceNo}</TableCell>
                    <TableCell>{row.invoiceDate}</TableCell>
                    <TableCell>{row.supplierName}</TableCell>
                    <TableCell align="right">₹{row.totalAmount?.toFixed(2)}</TableCell>
                    <TableCell align="right">₹{row.discountAmount?.toFixed(2)}</TableCell>
                    <TableCell align="right">₹{row.taxAmount?.toFixed(2)}</TableCell>
                    <TableCell align="right">
                      <Typography fontWeight="bold" color="primary">
                        ₹{row.netAmount?.toFixed(2)}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Chip
                        label={row.paymentType}
                        color={row.paymentType === 'CASH' ? 'success' : 'warning'}
                        size="small"
                      />
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        </Paper>
      ) : (
        <Paper sx={{ p: 4, textAlign: 'center', borderRadius: 2 }}>
          <Typography color="textSecondary">
            No purchase data found for the selected period
          </Typography>
        </Paper>
      )}
    </Box>
  );
};

export default PurchaseReport;
